1	const PROCESSING_FEE_G = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE_G = 60;
4	const COMPONENT_UNIT_PRICE_G = 25;
5	
6	const MAIN_ITEM_BASE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	const ITEM_INSURANCE_VALUE: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	  staff: 800,
16	  potion: 400,
17	  rune: 250,
18	  moonstone: 250,
19	};
20	const DEDUCTIBLE_G = 100;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = { type: string; cursed?: boolean; enchantment?: number };
24	type Damage = { itemType: string; amount: number };
25	type QuoteStep = { op: "quote"; items: Item[] };
26	type ClaimStep = { op: "claim"; policy: number; incident: { cause?: string; damages: Damage[] } };
27	type Step = QuoteStep | ClaimStep;
28	type Scenario = {
29	  customer: { yearsWithMHPCO: number };
30	  steps: Step[];
31	};
32	
33	const sum = (numbers: number[]): number =>
34	  numbers.reduce((acc, n) => acc + n, 0);
35	
36	const componentBaseForGroup = (count: number): number =>
37	  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;
38	
39	const countByType = <T>(items: T[], typeOf: (item: T) => string): Map<string, number> => {
40	  const counts = new Map<string, number>();
41	  for (const item of items) {
42	    counts.set(typeOf(item), (counts.get(typeOf(item)) ?? 0) + 1);
43	  }
44	  return counts;
45	};
46	
47	const componentBaseTotal = (componentItems: Item[]): number => {
48	  const counts = countByType(componentItems, (i) => i.type);
49	  return sum([...counts.values()].map(componentBaseForGroup));
50	};
51	
52	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;
53	
54	const CURSE_RATE = 0.5;
55	const HIGH_ENCHANTMENT_RATE = 0.3;
56	const HIGH_ENCHANTMENT_THRESHOLD = 5;
57	
58	const isCursed = (item: Item): boolean => item.cursed === true;
59	const isHighlyEnchanted = (item: Item): boolean =>
60	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
61	
62	const mainItemModifiers = (item: Item): number => {
63	  const base = mainItemBase(item);
64	  const rate =
65	    (isCursed(item) ? CURSE_RATE : 0) +
66	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
67	  return base * rate;
68	};
69	
70	const firstInsuranceSurcharge = (policyBase: number): number => policyBase / 10;
71	
72	const loyaltyDiscount = (policyBase: number, yearsWithMHPCO: number): number =>
73	  yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
74	
75	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
76	
77	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
78	  isFollowUp ? policyBase * 0.15 : 0;
79	
80	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
81	  const mainItems = items.filter((i) => !isComponent(i));
82	  const componentItems = items.filter(isComponent);
83	  const policyBase = sum(mainItems.map(mainItemBase)) + componentBaseTotal(componentItems);
84	  const itemModifiersTotal = sum(mainItems.map(mainItemModifiers));
85	  const surcharges = firstInsuranceSurcharge(policyBase);
86	  const discounts = loyaltyDiscount(policyBase, yearsWithMHPCO) + followUpDiscount(policyBase, isFollowUp);
87	  return Math.ceil(policyBase + itemModifiersTotal + surcharges - discounts + PROCESSING_FEE_G);
88	};
89	
90	const insuranceSum = (items: Item[]): number =>
91	  sum(items.map((i) => ITEM_INSURANCE_VALUE[i.type] ?? 0));
92	
93	type Policy = { items: Item[]; remainingCap: number };
94	
95	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
96	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
97	
98	const isHighEnchantmentClaim = (item: Item | undefined): boolean =>
99	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
100	
101	const findDamagedItem = (damage: Damage, items: Item[]): Item | undefined =>
102	  items.find((i) => i.type === damage.itemType);
103	
104	const effectiveDamageAmount = (damage: Damage, items: Item[]): number => {
105	  const item = findDamagedItem(damage, items);
106	  return isHighEnchantmentClaim(item)
107	    ? Math.floor(damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE)
108	    : damage.amount;
109	};
110	
111	const damagePayout = (damage: Damage, remainingCap: number, items: Item[]): number =>
